import React, { useState, useMemo } from "react";
import {
  Container,
  Row,
  Col,
  Form,
  Button,
  Card,
  ListGroup,
} from "react-bootstrap";
import { useProvider } from "./useProvider";

const Movies = () => {
  return (
    <Container>
      <h1>React Application</h1>
      <hr />
      <div>---</div>
      <hr />
      <Row>
        <Col xs={3}>
          <h2>Producers</h2>
        </Col>
      </Row>
    </Container>
  );
};

export default Movies;
